#include <bit>
#include <cstdint>
#include <iostream>
#include <format>

int main() {
    // bit_cast: reinterpret float bits as uint32 without UB
    float f = 1.0f;
    uint32_t bits = std::bit_cast<uint32_t>(f);
    std::cout << std::format("1.0f bits: 0x{:08X}\n", bits);  // 0x3F800000

    // Reverse: construct float from specific bits
    uint32_t neg_one_bits = 0xBF800000u;
    float neg_one = std::bit_cast<float>(neg_one_bits);
    std::cout << "reconstructed: " << neg_one << "\n";  // -1

    // constexpr bit_cast
    constexpr uint32_t pi_bits = std::bit_cast<uint32_t>(3.14159265f);
    std::cout << std::format("pi bits: 0x{:08X}\n", pi_bits);

    // Check IEEE 754 sign bit
    auto check_negative = [](float x) {
        return (std::bit_cast<uint32_t>(x) >> 31) == 1;
    };
    std::cout << "is -3.5 negative: " << check_negative(-3.5f) << "\n";  // 1
    std::cout << "is  3.5 negative: " << check_negative( 3.5f) << "\n";  // 0
}

#include <source_location>
#include <numbers>
#include <iostream>
#include <format>
#include <cmath>
#include <string_view>

void log(std::string_view msg,
         std::source_location loc = std::source_location::current()) {
    std::cout << std::format("[{}:{}] {}\n",
                             loc.file_name(), loc.line(), msg);
}

int main() {
    log("program started");
    log("computing area");

    // std::numbers constants
    double r = 5.0;
    double area = std::numbers::pi * r * r;
    std::cout << std::format("pi  = {:.10f}\n", std::numbers::pi);
    std::cout << std::format("e   = {:.10f}\n", std::numbers::e);
    std::cout << std::format("sqrt2 = {:.10f}\n", std::numbers::sqrt2);
    std::cout << std::format("circle area r=5: {:.4f}\n", area);

    // Template variant for custom precision
    long double pi_ld = std::numbers::pi_v<long double>;
    std::cout << std::format("pi (long double) = {:.15Lf}\n", pi_ld);
}

#include <numeric>
#include <cmath>
#include <iostream>
#include <format>
#include <cstdint>

int main() {
    // midpoint: safe average for integers
    int32_t a = 2000000000, b = 2000000001;
    std::cout << "midpoint: " << std::midpoint(a, b) << "\n";  // 2000000000

    // Wrong way: overflows!
    // int overflow_bug = (a + b) / 2;  // UB: signed overflow

    // midpoint for floating point
    std::cout << std::format("midpoint(1.0, 3.0) = {}\n", std::midpoint(1.0, 3.0));  // 2

    // lerp: linear interpolation
    std::cout << std::format("lerp(0, 10, 0.3) = {}\n", std::lerp(0.0, 10.0, 0.3));
    std::cout << std::format("lerp(0, 10, 0.5) = {}\n", std::lerp(0.0, 10.0, 0.5));
    std::cout << std::format("lerp(0, 10, 1.0) = {}\n", std::lerp(0.0, 10.0, 1.0));

    // lerp guarantees exact values at t=0 and t=1
    std::cout << std::format("lerp(1.5, 3.5, 0.0) = {}\n", std::lerp(1.5, 3.5, 0.0));  // 1.5
    std::cout << std::format("lerp(1.5, 3.5, 1.0) = {}\n", std::lerp(1.5, 3.5, 1.0));  // 3.5
}

#include <vector>
#include <list>
#include <map>
#include <algorithm>
#include <memory>
#include <iostream>
#include <format>

int main() {
    // erase_if: clean replacement for erase-remove idiom
    std::vector<int> v{1, 2, 3, 4, 5, 6, 7, 8};
    std::erase_if(v, [](int x) { return x % 2 == 0; });
    std::cout << "after erase even: ";
    for (int x : v) std::cout << x << " ";
    std::cout << "\n";

    // erase by value
    std::vector<int> v2{1, 3, 2, 3, 4, 3};
    std::erase(v2, 3);
    std::cout << "after erase 3: ";
    for (int x : v2) std::cout << x << " ";
    std::cout << "\n";

    // works on std::list too
    std::list<std::string> words{"hello", "world", "foo", "bar", "baz"};
    std::erase_if(words, [](const std::string& s) { return s.size() <= 3; });
    std::cout << "long words: ";
    for (auto& w : words) std::cout << w << " ";
    std::cout << "\n";

    // to_address: get raw pointer from smart/fancy pointer
    auto sp = std::make_unique<int>(42);
    int* raw = std::to_address(sp);  // same as sp.get()
    std::cout << "via to_address: " << *raw << "\n";

    // to_address also works on raw iterators/pointers
    std::vector<int> nums{10, 20, 30};
    auto it = nums.begin();
    int* p = std::to_address(it);
    std::cout << "first element: " << *p << "\n";
}

#include <string>
#include <map>
#include <set>
#include <iostream>

int main() {
    std::string url = "https://example.com/api/v2";

    std::cout << std::boolalpha;
    std::cout << "starts with https: " << url.starts_with("https") << "\n";  // true
    std::cout << "ends with v2:      " << url.ends_with("v2") << "\n";        // true
    std::cout << "starts with http:  " << url.starts_with("http") << "\n";    // true (prefix!)
    std::cout << "ends with .html:   " << url.ends_with(".html") << "\n";     // false

    // string_view overload
    std::string_view suffix = "/v2";
    std::cout << "ends with /v2: " << url.ends_with(suffix) << "\n";

    // map::contains (C++20)
    std::map<std::string, int> config{{"timeout", 30}, {"retries", 3}};
    std::cout << "has timeout: " << config.contains("timeout") << "\n";   // true
    std::cout << "has debug:   " << config.contains("debug") << "\n";     // false

    // set::contains
    std::set<int> primes{2, 3, 5, 7, 11};
    std::cout << "7 is prime: " << primes.contains(7) << "\n";   // true
    std::cout << "9 is prime: " << primes.contains(9) << "\n";   // false
}

#include <type_traits>
#include <memory>
#include <functional>
#include <algorithm>
#include <vector>
#include <iostream>
#include <string>

int main() {
    // remove_cvref_t: strips const, volatile, and reference in one shot
    using T1 = std::remove_cvref_t<const int&>;   // int
    using T2 = std::remove_cvref_t<volatile int&&>; // int
    using T3 = std::remove_cvref_t<const volatile int*>; // const volatile int* (pointer not stripped)

    std::cout << std::boolalpha;
    std::cout << "remove_cvref_t<const int&> == int: "
              << std::is_same_v<T1, int> << "\n";  // true
    std::cout << "remove_cvref_t<volatile int&&> == int: "
              << std::is_same_v<T2, int> << "\n";  // true

    // is_bounded_array vs is_unbounded_array
    std::cout << "int[5] bounded: " << std::is_bounded_array_v<int[5]> << "\n";    // true
    std::cout << "int[]  unbounded: " << std::is_unbounded_array_v<int[]> << "\n"; // true
    std::cout << "int    bounded: " << std::is_bounded_array_v<int> << "\n";       // false

    // std::identity: default projector
    std::vector<int> v{3, 1, 4, 1, 5, 9, 2, 6};
    std::ranges::sort(v, std::less{}, std::identity{});  // sort by identity (i.e., by value)
    std::cout << "sorted: ";
    for (int x : v) std::cout << x << " ";
    std::cout << "\n";

    // make_shared_for_overwrite: uninitialized memory
    auto buf = std::make_shared_for_overwrite<int[]>(5);
    for (int i = 0; i < 5; ++i) buf[i] = i * i;
    std::cout << "squares: ";
    for (int i = 0; i < 5; ++i) std::cout << buf[i] << " ";
    std::cout << "\n";
}
